1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: empty and single items
6	  it("empty item list yields premium of 5 G (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it.todo("single sword (no modifiers, first-time customer) yields 115 G (100 base + 10 first + 5 fee)");
14	  it.todo("single amulet yields 71 G (60 base + 6 first + 5 fee, rounded up)");
15	  it.todo("single staff yields 93 G (80 base + 8 first + 5 fee)");
16	  it.todo("single potion yields 49 G (40 base + 4 first + 5 fee)");
17	
18	  // Components
19	  it.todo("single rune yields 33 G (25 base + 2.5 first rounded up + 5 fee = 32.5 -> 33)");
20	  it.todo("3 alike runes form a block: 60 G base premium");
21	  it.todo("4 runes do not form a block: 100 G base premium");
22	  it.todo("2 runes + 1 moonstone: no block (different types), 75 G base premium");
23	  it.todo("3 runes + 3 moonstones: two separate blocks, 120 G base premium");
24	
25	  // Item-specific modifiers
26	  it.todo("cursed sword adds 50% surcharge on item base premium (newcomer cursed sword: 165 G)");
27	  it.todo("high enchantment (>=5) sword adds 30% surcharge");
28	  it.todo("enchantment 4 sword does not add high-enchantment surcharge");
29	  it.todo("cursed AND high-enchantment sword stacks both surcharges");
30	
31	  // Policy-wide modifiers
32	  it.todo("loyalty discount (>=2 years) applies 20% off the policy base premium");
33	  it.todo("exactly 2 years customer receives loyalty discount");
34	  it.todo("follow-up contract (second quote in scenario) applies 15% discount");
35	  it.todo("first-insurance surcharge applies per item even for follow-up contracts");
36	
37	  // Multi-item modifier scope
38	  it.todo("cursed surcharge applies only to cursed item, not whole policy");
39	
40	  // Rounding
41	  it.todo("premium rounds up in MHPCO's favor");
42	
43	  // Integration examples
44	  it.todo("newcomer with cursed sword: 165 G");
45	  it.todo("long-standing customer's second contract with cursed enchantment-7 sword: 160 G");
46	
47	  // Claim: basic payouts
48	  it.todo("regular sword damage 500 G yields payout 400 G (minus 100 deductible)");
49	  it.todo("damage to rune (250 G value) of 200 G yields payout 100 G");
50	  it.todo("high-enchantment (>=8) item: 50% reimbursement then deductible");
51	  it.todo("dragon material item: full reimbursement then deductible");
52	  it.todo("dragon material with enchantment 9: 50% wins, then deductible");
53	
54	  // Claim: cap and deductible
55	  it.todo("payout capped at 2x insurance sum across multiple claims");
56	  it.todo("deductible applies per damaged item entry");
57	  it.todo("two-sword policy: insurance sum 2000, cap 4000");
58	  it.todo("payout rounds down in MHPCO's favor");
59	
60	  // Errors
61	  it.todo("quote with unknown item type causes non-zero exit");
62	  it.todo("claim against item not in policy causes non-zero exit");
63	  it.todo("claim with negative damage amount causes non-zero exit");
64	  it.todo("more damages of a type than insured items causes non-zero exit");
65	
66	  // CLI
67	  it.todo("CLI reads JSON from stdin and writes results JSON to stdout");
68	});
